190	static void tpu_forward()
191	{
192		u32 ret;
193		u32 rd_val;
194	
195	    EEPTPU_BASEADDR0_REG=waddr;
196	#ifdef EEP_DEBUG_INFO
197	    rd_val = EEPTPU_BASEADDR0_REG;
198		xil_printf("EEPTPU_BASEADDR0_REG value: 0x%08x\r\n", rd_val);
199	#endif
200	    EEPTPU_BASEADDR1_REG=sd_input_addr;
201	#ifdef EEP_DEBUG_INFO
202	    rd_val = EEPTPU_BASEADDR1_REG;
203	    xil_printf("EEPTPU_BASEADDR1_REG value: 0x%08x\r\n", rd_val);
204	#endif
205	    EEPTPU_BASEADDR2_REG=tpu_hwbase2;
206	#ifdef EEP_DEBUG_INFO
207	    rd_val = EEPTPU_BASEADDR2_REG;
208	    xil_printf("EEPTPU_BASEADDR2_REG value: 0x%08x\r\n", rd_val);
209	#endif
210	    EEPTPU_BASEADDR3_REG=tpu_hwbase3;
211	#ifdef EEP_DEBUG_INFO
212	    rd_val = EEPTPU_BASEADDR3_REG;
213	    xil_printf("EEPTPU_BASEADDR3_REG value: 0x%08x\r\n", rd_val);
214	#endif
215	    EEPTPU_ALGOADDR_REG=tpu_algbase;
216	#ifdef EEP_DEBUG_INFO
217	    rd_val = EEPTPU_ALGOADDR_REG;
218	    xil_printf("EEPTPU_ALGOADDR_REG value: 0x%08x\r\n", rd_val);
219	#endif
220	    EEPTPU_STARTUP_REG=0x11;
221	
222	    rd_val=EEPTPU_STATUS_REG;
223	    while( (rd_val & 0x80000000) != 0x80000000 )
224	    {
225	    	rd_val=EEPTPU_STATUS_REG;
226	    	ret = 0;
227	    }
228	}
