608					    	xil_printf("yolo3 detection output fail\r\n");
609					    	top_blobs.clear();
610						    outputs.clear();
611						    eepsa.eeptpu_deinit();
612					    	continue;
613					    }
614		                #ifdef EEP_DEBUG_INFO
615					    xil_printf("Forwarding done.\r\n");
616		                #endif
617					    xil_printf("forward time is %d us\r\n", tused_forward);
618					    xil_printf("detection output time is %d us\r\n", tused_det_out);
619					    // show result.
620					    blob_out = top_blobs[0];
621					#ifdef IMG_RGB565
622					    for (int i = 0; i < blob_out.h; i++)
623					    {
624					        const float *values = blob_out.row(i);
625	
626					        int label = values[0];
