24	using namespace ncnn;
25	
26	static void resize_bilinear_c1(const unsigned char* src, int srcw, int srch, int srcstride, unsigned char* dst, int w, int h, int stride)
27	{
28	    const int INTER_RESIZE_COEF_BITS = 11;
29	    const int INTER_RESIZE_COEF_SCALE = 1 << INTER_RESIZE_COEF_BITS;
30	    //     const int ONE=INTER_RESIZE_COEF_SCALE;
31	
32	    double scale_x = (double)srcw / w;
33	    double scale_y = (double)srch / h;
34	
35	    int* buf = new int[w + h + w + h];
36	
37	    int* xofs = buf;     //new int[w];
38	    int* yofs = buf + w; //new int[h];
39	
40	    short* ialpha = (short*)(buf + w + h);    //new short[w * 2];
41	    short* ibeta = (short*)(buf + w + h + w); //new short[h * 2];
42	
43	    float fx;
44	    float fy;
45	    int sx;
46	    int sy;
47	
48	#define SATURATE_CAST_SHORT(X) (short)::std::min(::std::max((int)(X + (X >= 0.f ? 0.5f : -0.5f)), SHRT_MIN), SHRT_MAX);
49	
50	    for (int dx = 0; dx < w; dx++)
51	    {
52	        fx = (float)((dx + 0.5) * scale_x - 0.5);
53	        sx = static_cast<int>(floor(fx));
54	        fx -= sx;
55	
56	        if (sx < 0)
57	        {
58	            sx = 0;
59	            fx = 0.f;
60	        }
61	        if (sx >= srcw - 1)
62	        {
63	            sx = srcw - 2;
64	            fx = 1.f;
65	        }
66	
67	        xofs[dx] = sx;
68	
69	        float a0 = (1.f - fx) * INTER_RESIZE_COEF_SCALE;
70	        float a1 = fx * INTER_RESIZE_COEF_SCALE;
71	
72	        ialpha[dx * 2] = SATURATE_CAST_SHORT(a0);
73	        ialpha[dx * 2 + 1] = SATURATE_CAST_SHORT(a1);
74	    }
75	
76	    for (int dy = 0; dy < h; dy++)
77	    {
78	        fy = (float)((dy + 0.5) * scale_y - 0.5);
79	        sy = static_cast<int>(floor(fy));
80	        fy -= sy;
81	
82	        if (sy < 0)
83	        {
84	            sy = 0;
85	            fy = 0.f;
86	        }
87	        if (sy >= srch - 1)
88	        {
89	            sy = srch - 2;
90	            fy = 1.f;
91	        }
92	
93	        yofs[dy] = sy;
94	
95	        float b0 = (1.f - fy) * INTER_RESIZE_COEF_SCALE;
96	        float b1 = fy * INTER_RESIZE_COEF_SCALE;
97	
98	        ibeta[dy * 2] = SATURATE_CAST_SHORT(b0);
99	        ibeta[dy * 2 + 1] = SATURATE_CAST_SHORT(b1);
100	    }
101	
102	#undef SATURATE_CAST_SHORT
103	
104	    // loop body
105	    Mat rowsbuf0(w, (size_t)2u);
106	    Mat rowsbuf1(w, (size_t)2u);
107	    short* rows0 = (short*)rowsbuf0.data;
108	    short* rows1 = (short*)rowsbuf1.data;
109	
110	    int prev_sy1 = -2;
111	
112	    for (int dy = 0; dy < h; dy++)
113	    {
114	        int sy = yofs[dy];
115	
116	        if (sy == prev_sy1)
117	        {
118	            // reuse all rows
119	        }
120	        else if (sy == prev_sy1 + 1)
121	        {
122	            // hresize one row
123	            short* rows0_old = rows0;
124	            rows0 = rows1;
125	            rows1 = rows0_old;
126	            const unsigned char* S1 = src + srcstride * (sy + 1);
127	
128	            const short* ialphap = ialpha;
129	            short* rows1p = rows1;
130	            for (int dx = 0; dx < w; dx++)
131	            {
132	                int sx = xofs[dx];
133	                short a0 = ialphap[0];
134	                short a1 = ialphap[1];
135	
136	                const unsigned char* S1p = S1 + sx;
137	                rows1p[dx] = (S1p[0] * a0 + S1p[1] * a1) >> 4;
138	
139	                ialphap += 2;
140	            }
141	        }
142	        else
143	        {
144	            // hresize two rows
145	            const unsigned char* S0 = src + srcstride * (sy);
146	            const unsigned char* S1 = src + srcstride * (sy + 1);
147	
148	            const short* ialphap = ialpha;
149	            short* rows0p = rows0;
150	            short* rows1p = rows1;
151	            for (int dx = 0; dx < w; dx++)
152	            {
153	                int sx = xofs[dx];
154	                short a0 = ialphap[0];
155	                short a1 = ialphap[1];
156	
157	                const unsigned char* S0p = S0 + sx;
158	                const unsigned char* S1p = S1 + sx;
159	                rows0p[dx] = (S0p[0] * a0 + S0p[1] * a1) >> 4;
160	                rows1p[dx] = (S1p[0] * a0 + S1p[1] * a1) >> 4;
161	
162	                ialphap += 2;
163	            }
164	        }
165	
166	        prev_sy1 = sy;
167	
168	        // vresize
169	        short b0 = ibeta[0];
170	        short b1 = ibeta[1];
171	
172	        short* rows0p = rows0;
173	        short* rows1p = rows1;
174	        unsigned char* Dp = dst + stride * (dy);
175	
176	        int nn = 0;
177	        int remain = w - (nn << 3);
178	
179	        for (; remain; --remain)
180	        {
181	            //             D[x] = (rows0[x]*b0 + rows1[x]*b1) >> INTER_RESIZE_COEF_BITS;
182	            *Dp++ = (unsigned char)(((short)((b0 * (short)(*rows0p++)) >> 16) + (short)((b1 * (short)(*rows1p++)) >> 16) + 2) >> 2);
183	        }
184	
185	        ibeta += 2;
186	    }
187	
188	    delete[] buf;
189	}
