191	static void resize_bilinear_c3(const unsigned char* src, int srcw, int srch, int srcstride, unsigned char* dst, int w, int h, int stride)
192	{
193	    const int INTER_RESIZE_COEF_BITS = 11;
194	    const int INTER_RESIZE_COEF_SCALE = 1 << INTER_RESIZE_COEF_BITS;
195	    //     const int ONE=INTER_RESIZE_COEF_SCALE;
196	
197	    double scale_x = (double)srcw / w;
198	    double scale_y = (double)srch / h;
199	
200	    int* buf = new int[w + h + w + h];
201	
202	    int* xofs = buf;     //new int[w];
203	    int* yofs = buf + w; //new int[h];
204	
205	    short* ialpha = (short*)(buf + w + h);    //new short[w * 2];
206	    short* ibeta = (short*)(buf + w + h + w); //new short[h * 2];
207	
208	    float fx;
209	    float fy;
210	    int sx;
211	    int sy;
212	
213	#define SATURATE_CAST_SHORT(X) (short)::std::min(::std::max((int)(X + (X >= 0.f ? 0.5f : -0.5f)), SHRT_MIN), SHRT_MAX);
214	
215	    for (int dx = 0; dx < w; dx++)
216	    {
217	        fx = (float)((dx + 0.5) * scale_x - 0.5);
218	        sx = static_cast<int>(floor(fx));
219	        fx -= sx;
220	
221	        if (sx < 0)
222	        {
223	            sx = 0;
224	            fx = 0.f;
225	        }
226	        if (sx >= srcw - 1)
227	        {
228	            sx = srcw - 2;
229	            fx = 1.f;
230	        }
231	
232	        xofs[dx] = sx * 3;
233	
234	        float a0 = (1.f - fx) * INTER_RESIZE_COEF_SCALE;
235	        float a1 = fx * INTER_RESIZE_COEF_SCALE;
236	
237	        ialpha[dx * 2] = SATURATE_CAST_SHORT(a0);
238	        ialpha[dx * 2 + 1] = SATURATE_CAST_SHORT(a1);
239	    }
240	
241	    for (int dy = 0; dy < h; dy++)
242	    {
243	        fy = (float)((dy + 0.5) * scale_y - 0.5);
244	        sy = static_cast<int>(floor(fy));
245	        fy -= sy;
246	
247	        if (sy < 0)
248	        {
249	            sy = 0;
250	            fy = 0.f;
251	        }
252	        if (sy >= srch - 1)
253	        {
254	            sy = srch - 2;
255	            fy = 1.f;
256	        }
257	
258	        yofs[dy] = sy;
259	
260	        float b0 = (1.f - fy) * INTER_RESIZE_COEF_SCALE;
261	        float b1 = fy * INTER_RESIZE_COEF_SCALE;
262	
263	        ibeta[dy * 2] = SATURATE_CAST_SHORT(b0);
264	        ibeta[dy * 2 + 1] = SATURATE_CAST_SHORT(b1);
265	    }
266	
267	#undef SATURATE_CAST_SHORT
268	
269	    // loop body
270	    Mat rowsbuf0(w * 3 + 1, (size_t)2u);
271	    Mat rowsbuf1(w * 3 + 1, (size_t)2u);
272	    short* rows0 = (short*)rowsbuf0.data;
273	    short* rows1 = (short*)rowsbuf1.data;
274	
275	    int prev_sy1 = -2;
276	
277	    for (int dy = 0; dy < h; dy++)
278	    {
279	        int sy = yofs[dy];
280	
281	        if (sy == prev_sy1)
282	        {
283	            // reuse all rows
284	        }
285	        else if (sy == prev_sy1 + 1)
286	        {
287	            // hresize one row
288	            short* rows0_old = rows0;
289	            rows0 = rows1;
290	            rows1 = rows0_old;
291	            const unsigned char* S1 = src + srcstride * (sy + 1);
292	
293	            const short* ialphap = ialpha;
294	            short* rows1p = rows1;
295	            for (int dx = 0; dx < w; dx++)
296	            {
297	                int sx = xofs[dx];
298	                short a0 = ialphap[0];
299	                short a1 = ialphap[1];
300	
301	                const unsigned char* S1p = S1 + sx;
302	
303	                rows1p[0] = (S1p[0] * a0 + S1p[3] * a1) >> 4;
304	                rows1p[1] = (S1p[1] * a0 + S1p[4] * a1) >> 4;
305	                rows1p[2] = (S1p[2] * a0 + S1p[5] * a1) >> 4;
306	
307	                ialphap += 2;
308	                rows1p += 3;
309	            }
310	        }
311	        else
312	        {
313	            // hresize two rows
314	            const unsigned char* S0 = src + srcstride * (sy);
315	            const unsigned char* S1 = src + srcstride * (sy + 1);
316	
317	            const short* ialphap = ialpha;
318	            short* rows0p = rows0;
319	            short* rows1p = rows1;
320	            for (int dx = 0; dx < w; dx++)
321	            {
322	                int sx = xofs[dx];
323	                short a0 = ialphap[0];
324	                short a1 = ialphap[1];
325	
326	                const unsigned char* S0p = S0 + sx;
327	                const unsigned char* S1p = S1 + sx;
328	
329	                rows0p[0] = (S0p[0] * a0 + S0p[3] * a1) >> 4;
330	                rows0p[1] = (S0p[1] * a0 + S0p[4] * a1) >> 4;
331	                rows0p[2] = (S0p[2] * a0 + S0p[5] * a1) >> 4;
332	                rows1p[0] = (S1p[0] * a0 + S1p[3] * a1) >> 4;
333	                rows1p[1] = (S1p[1] * a0 + S1p[4] * a1) >> 4;
334	                rows1p[2] = (S1p[2] * a0 + S1p[5] * a1) >> 4;
335	
336	                ialphap += 2;
337	                rows0p += 3;
338	                rows1p += 3;
339	            }
340	        }
341	
342	        prev_sy1 = sy;
343	
344	        // vresize
345	        short b0 = ibeta[0];
346	        short b1 = ibeta[1];
347	
348	        short* rows0p = rows0;
349	        short* rows1p = rows1;
350	        unsigned char* Dp = dst + stride * (dy);
351	
352	        int nn = 0;
353	        int remain = (w * 3) - (nn << 3);
354	
355	        for (; remain; --remain)
356	        {
357	            //             D[x] = (rows0[x]*b0 + rows1[x]*b1) >> INTER_RESIZE_COEF_BITS;
358	            *Dp++ = (unsigned char)(((short)((b0 * (short)(*rows0p++)) >> 16) + (short)((b1 * (short)(*rows1p++)) >> 16) + 2) >> 2);
359	        }
360	
361	        ibeta += 2;
362	    }
363	
364	    delete[] buf;
365	}
366	
367	void resize_bilinear_c1(const unsigned char* src, int srcw, int srch, unsigned char* dst, int w, int h)
368	{
369	    return resize_bilinear_c1(src, srcw, srch, srcw, dst, w, h, w);
370	}
371	
372	void resize_bilinear_c3(const unsigned char* src, int srcw, int srch, unsigned char* dst, int w, int h)
373	{
374	    return resize_bilinear_c3(src, srcw, srch, srcw * 3, dst, w, h, w * 3);
375	}
